custom_css:
::selection { background: rgba(232, 35, 74, 0.3); color: #ffffff; }

[data-theme="halftone-dimension"] .bg-accent { box-shadow: 0 0 20px rgba(232, 35, 74, 0.4), 0 0 40px rgba(232, 35, 74, 0.15); }

[data-theme="halftone-dimension"] .chat-bubble.assistant { border-left: 3px solid #e8234a; }
[data-theme="halftone-dimension"] .chat-bubble.assistant:nth-child(odd) { border-left-color: #00b8ff; }

[data-theme="halftone-dimension"] .header-bar { border-color: rgba(232, 35, 74, 0.4); }
[data-theme="halftone-dimension"] .input-bar-container { border-color: rgba(232, 35, 74, 0.4); }

[data-theme="halftone-dimension"] button:focus-visible, [data-theme="halftone-dimension"] a:focus-visible, [data-theme="halftone-dimension"] select:focus-visible { outline: 2px solid #e8234a; outline-offset: 2px; box-shadow: 0 0 8px rgba(232, 35, 74, 0.3); }

[data-theme="halftone-dimension"] h1,
[data-theme="halftone-dimension"] h2,
[data-theme="halftone-dimension"] .header-bar { text-shadow: -1.5px 0 rgba(232, 35, 74, 0.4), 1.5px 0 rgba(0, 184, 255, 0.4); }

[data-theme="halftone-dimension"] .send-btn { box-shadow: 0 0 12px rgba(232, 35, 74, 0.5), 0 0 24px rgba(232, 35, 74, 0.2); }

[data-theme="halftone-dimension"] .chat-bubble.user { box-shadow: 0 0 18px rgba(232, 35, 74, 0.3), 0 0 40px rgba(232, 35, 74, 0.1); border: 1.5px solid rgba(232, 35, 74, 0.5); }

::-webkit-scrollbar-thumb { background-image: url('assets/scrollbar-thumb.svg'); background-size: contain; background-repeat: repeat-y; }
::-webkit-scrollbar-track { background: transparent; }
